```javascript
function solve(n, k) {
    if (k === 0) {
        return n >= 1 ? 1 : 0;
    }

    // Precompute the popcount-depth for numbers up to a certain limit (like 60 bits)
    const maxBits = 60;
    const depth = new Array(maxBits + 1).fill(0);
    depth[1] = 0;
    for (let i = 2; i <= maxBits; i++) {
        const next = i.toString(2).split('1').length - 1;
        depth[i] = depth[next] + 1;
    }

    // Memoization for the DP function
    const memo = new Map();

    function dp(pos, count, tight, bits) {
        if (pos === -1) {
            return count === 0 && depth[bits] === k - 1 ? 1 : 0;
        }
        const key = `${pos},${count},${tight},${bits}`;
        if (memo.has(key)) {
            return memo.get(key);
        }

        const limit = tight ? (n >> BigInt(pos)) & 1n : 1;
        let res = 0;

        for (let d = 0; d <= limit; d++) {
            const newTight = tight && (d === limit);
            const newCount = count - (d === 1 ? 1 : 0);
            const newBits = bits + (d === 1 ? 1 : 0);
            if (newCount >= 0) {
                res += dp(pos - 1, newCount, newTight, newBits);
            }
        }

        memo.set(key, res);
        return res;
    }

    const totalBits = n.toString(2).length;
    let result = 0;

    // We need to find numbers with popcount m where depth[m] == k-1
    // So first, collect all m where depth[m] == k-1
    const targets = [];
    for (let m = 1; m <= maxBits; m++) {
        if (depth[m] === k - 1) {
            targets.push(m);
        }
    }

    for (const m of targets) {
        memo.clear();
        result += dp(totalBits - 1, m, true, 0);
    }

    return result;
}
